svg.script:
var r = document.getElementById('sr');
var g = document.getElementById('SweepGrad');
var sX=-500, eX=2250, dur=2800, pause=1800, tot=dur+pause, t0=null;
function ease(t){ return t<0.5 ? 2*t*t : -1+(4-2*t)*t; }
function fr(ts){
  if(!t0) t0=ts;
  var el=(ts-t0)%tot;
  var x = el<dur ? sX+ease(el/dur)*(eX-sX) : eX;
  g.setAttribute('x1', x);
  g.setAttribute('x2', x+500);
  r.setAttribute('x', x);
  requestAnimationFrame(fr);
}
requestAnimationFrame(fr);
